node -e "
const fs = require('fs');
const raw = fs.readFileSync('C:/Users/hara/.claude/projects/C--Users-hara--claude/24e52618-d8f2-40f6-b19c-e76a34fb7a3e/tool-results/mcp-33faa85e-e1f0-43e1-af87-302c68b58b3e-gmail_search_messages-1774935822229.txt', 'utf8');
const outer = JSON.parse(raw);
const inner = JSON.parse(outer[0].text);
const messages = inner.messages;
console.log('総メッセージ数:', messages.length);

const seen = new Set();
const contacts = [];

messages.forEach(msg => {
  const headers = msg.headers || {};
  const to = headers.To || '';
  const subject = headers.Subject || '';
  const date = headers.Date || '';

  const emailMatch = to.match(/[\w.\-+]+@[\w.\-]+\.[a-zA-Z]{2,}/g) || [];
  const nameMatch = to.match(/\"([^\"]+)\"/);
  const name = nameMatch ? nameMatch[1] : to.split('<')[0].trim();

  emailMatch.forEach(email => {
    const el = email.toLowerCase();
    if (el.includes('shuwan') || el.includes('matsukubo')) return;
    if (!seen.has(el)) {
      seen.add(el);
      contacts.push({ email, name, subject: subject.substring(0,35), date: date.substring(0,16) });
    }
  });
});

contacts.sort((a,b) => a.date.localeCompare(b.date));
contacts.forEach(c => console.log(c.date + ' | ' + c.name + ' | ' + c.email + ' | ' + c.subject));
"

