const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = "LAYOUT_16x9";
pres.title = "SHUWAN YouTube戦略 社内答申";

// ── カラー定数 ──────────────────────────────
const NAVY   = "1F3864";
const GOLD   = "C9A84C";
const WHITE  = "FFFFFF";
const LIGHT  = "F5F7FA";
const DARK   = "1A1A2E";
const GRAY   = "6B7280";
const LGRAY  = "E5E7EB";
const RED    = "DC2626";
const GREEN  = "16A34A";
const AMBER  = "D97706";

// ── ヘルパー: スライド共通ヘッダー(カラーバー+タイトル) ─────────
function addSlideHeader(slide, title, pres) {
  // 上部ネイビーバー
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.55,
    fill: { color: NAVY }, line: { color: NAVY }
  });
  // ゴールドアクセント（左端）
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.22, h: 0.55,
    fill: { color: GOLD }, line: { color: GOLD }
  });
  // タイトルテキスト
  slide.addText(title, {
    x: 0.32, y: 0, w: 9.5, h: 0.55,
    fontSize: 18, bold: true, color: WHITE,
    fontFace: "Calibri", valign: "middle", margin: 0
  });
  // スライド番号エリア（右）
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 9.5, y: 0, w: 0.5, h: 0.55,
    fill: { color: GOLD }, line: { color: GOLD }
  });
}

// ── ヘルパー: カードボックス ───────────────────────────
function addCard(slide, x, y, w, h, fillColor, pres) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h,
    fill: { color: fillColor || WHITE },
    line: { color: LGRAY, width: 0.8 },
    shadow: { type: "outer", color: "000000", blur: 5, offset: 2, angle: 135, opacity: 0.10 }
  });
}

// ══════════════════════════════════════════════════════════════
// スライド 1: 表紙
// ══════════════════════════════════════════════════════════════
const s1 = pres.addSlide();
s1.background = { color: NAVY };

// ゴールドの斜め装飾バー（背景アクセント）
s1.addShape(pres.shapes.RECTANGLE, {
  x: 7.2, y: 0, w: 2.8, h: 5.625,
  fill: { color: "162B50" }, line: { color: "162B50" }
});
s1.addShape(pres.shapes.RECTANGLE, {
  x: 8.8, y: 0, w: 0.2, h: 5.625,
  fill: { color: GOLD }, line: { color: GOLD }
});
s1.addShape(pres.shapes.RECTANGLE, {
  x: 9.1, y: 0, w: 0.12, h: 5.625,
  fill: { color: "C9A84C" }, line: { color: "C9A84C" }
});

// ゴールドライン（水平）
s1.addShape(pres.shapes.RECTANGLE, {
  x: 0.6, y: 2.55, w: 6.3, h: 0.06,
  fill: { color: GOLD }, line: { color: GOLD }
});

// タグライン
s1.addText("SHUWAN | 社内答申資料", {
  x: 0.6, y: 1.5, w: 7, h: 0.4,
  fontSize: 11, color: "A8B8D8", fontFace: "Calibri",
  charSpacing: 3
});

// メインタイトル
s1.addText("YouTube戦略", {
  x: 0.6, y: 1.9, w: 7.5, h: 0.85,
  fontSize: 46, bold: true, color: WHITE, fontFace: "Calibri"
});

// サブタイトル
s1.addText("サイト流入3,000達成に向けたコンテンツ戦略", {
  x: 0.6, y: 2.75, w: 7.5, h: 0.5,
  fontSize: 17, color: "CBD5E1", fontFace: "Calibri", italic: true
});

// 日付・会社
s1.addText([
  { text: "2026年4月　", options: { bold: false } },
  { text: "株式会社シュワン", options: { bold: true } }
], {
  x: 0.6, y: 4.8, w: 6, h: 0.4,
  fontSize: 12, color: "94A3B8", fontFace: "Calibri"
});

// ══════════════════════════════════════════════════════════════
// スライド 2: なぜYouTubeか
// ══════════════════════════════════════════════════════════════
const s2 = pres.addSlide();
s2.background = { color: WHITE };
addSlideHeader(s2, "なぜ今、YouTubeなのか", pres);

// 左カード: 現状課題
addCard(s2, 0.35, 0.75, 4.35, 4.55, "FEF2F2", pres);
s2.addShape(pres.shapes.RECTANGLE, {
  x: 0.35, y: 0.75, w: 4.35, h: 0.45,
  fill: { color: RED }, line: { color: RED }
});
s2.addText("現状の課題", {
  x: 0.35, y: 0.75, w: 4.35, h: 0.45,
  fontSize: 13, bold: true, color: WHITE, fontFace: "Calibri",
  align: "center", valign: "middle", margin: 0
});

// 課題の数値ハイライト
const issues = [
  { label: "月間購買ページ流入", val: "1,800", target: "目標 3,000（達成率60%）", c: RED },
  { label: "CVR", val: "3.5%", target: "目標 5%", c: AMBER },
  { label: "自社EC売上", val: "目標比 47%", target: "未達　大幅改善が必要", c: RED },
];
issues.forEach((item, i) => {
  const yy = 1.3 + i * 1.15;
  s2.addText(item.label, {
    x: 0.55, y: yy, w: 3.9, h: 0.3,
    fontSize: 10, color: GRAY, fontFace: "Calibri"
  });
  s2.addText(item.val, {
    x: 0.55, y: yy + 0.28, w: 3.9, h: 0.5,
    fontSize: 26, bold: true, color: item.c, fontFace: "Calibri"
  });
  s2.addText(item.target, {
    x: 0.55, y: yy + 0.75, w: 3.9, h: 0.28,
    fontSize: 10, color: GRAY, fontFace: "Calibri"
  });
});

// 2つの壁
s2.addText("▶ 購買を阻む「2つの壁」：知らない × 信じられない", {
  x: 0.45, y: 4.6, w: 4.15, h: 0.55,
  fontSize: 10, bold: true, color: RED, fontFace: "Calibri",
  fill: { color: "FEE2E2" }, margin: 6
});

// 右カード: YouTubeが解決
addCard(s2, 4.9, 0.75, 4.75, 4.55, "F0FDF4", pres);
s2.addShape(pres.shapes.RECTANGLE, {
  x: 4.9, y: 0.75, w: 4.75, h: 0.45,
  fill: { color: GREEN }, line: { color: GREEN }
});
s2.addText("YouTubeが解決する理由", {
  x: 4.9, y: 0.75, w: 4.75, h: 0.45,
  fontSize: 13, bold: true, color: WHITE, fontFace: "Calibri",
  align: "center", valign: "middle", margin: 0
});

const reasons = [
  { icon: "👁", head: "「知る」壁を突破", body: "動画で認知拡大・流入増\n検索＋アルゴリズム拡散の両輪" },
  { icon: "✅", head: "「信じる」壁を突破", body: "プロの使用シーン・科学的根拠を\n視覚的に証明 → CVR向上" },
  { icon: "🏆", head: "競合優位との相性", body: "「科学的根拠×プロ採用」の\n差別化は動画との相性が最高" },
  { icon: "🤝", head: "既存コラボ実績あり", body: "酒泉洞堀一チャンネル\n（登録1.63万人）での実績済み" },
];
reasons.forEach((r, i) => {
  const yy = 1.3 + i * 0.98;
  s2.addShape(pres.shapes.OVAL, {
    x: 5.05, y: yy + 0.05, w: 0.38, h: 0.38,
    fill: { color: "DCFCE7" }, line: { color: GREEN }
  });
  s2.addText(r.icon, {
    x: 5.05, y: yy + 0.04, w: 0.38, h: 0.38,
