    bold: true, margin: 0
  });
  s.addText("日本酒専用設計カテゴリにおける主要競合の詳細調査", {
    x: 0.8, y: 3.5, w: 8, h: 0.5,
    fontSize: 16, fontFace: "Calibri", color: C.sub,
    margin: 0
  });
  s.addShape(pres.shapes.LINE, {
    x: 0.8, y: 4.2, w: 5, h: 0,
    line: { color: C.accent3, width: 2 }
