  // Final goal bar
  s.addShape(pres.shapes.RECTANGLE, { x: 0.5, y: 6.65, w: 12.3, h: 0.5,
    fill: { color: "FFF3CD" }, line: { color: C.accent6, width: 1.5 } });
  s.addText(
