    s.addText(it.label, { x: 0.85, y: 2.42 + i * 1.3, w: 4.8, h: 0.3,
      fontSize: 11, fontFace: "Calibri", color: i === 2 ? C.accent4 : C.accent3, bold: true, margin: 0 });
    s.addText(it.val, { x: 0.85, y: 2.72 + i * 1.3, w: 4.8, h: 0.55,
